import math
class Solution:
    def minimumReplacement(self, nums):
        limit = nums[-1]
        ops = 0
        for v in reversed(nums[:-1]):
            if v <= limit:
                limit = v
                continue
            parts = 1
            while math.ceil(v / parts) > limit:
                parts += 1
            ops += parts - 1
            limit = v // parts
        return ops

