class Solution:
    def minimumReplacement(self, nums):
        limit = nums[-1]
        ops = 0
        for i in range(len(nums) - 2, -1, -1):
            v = nums[i]
            if v <= limit:
                limit = v
            else:
                parts = (v + limit - 1) // limit
                ops += parts - 1
                limit = v // parts
        return ops

