var minimumReplacement = function(nums) {
    let limit = nums[nums.length - 1];
    let ops = 0;
    for (let i = nums.length - 2; i >= 0; i--) {
        const v = nums[i];
        if (v <= limit) {
            limit = v;
        } else {
            const parts = Math.floor((v + limit - 1) / limit);
            ops += parts - 1;
            limit = Math.floor(v / parts);
        }
    }
    return ops;
};
